'use client'

import * as React from 'react'

export function NodeModuleClientWidget(props) {
  const [count, setCount] = React.useState(0)

  return React.createElement(
    'button',
    {
      type: 'button',
      'data-testid': 'node-module-client-widget',
      onClick: () => setCount((value) => value + 1),
    },
    `${props.label}: ${count}`,
  )
}
